const inferStateSurface = (state) => {
  if (state.phone?.gate) return "pre_chat_gate";
  if (state.phone?.overlay?.mode === "today-drawer") return "today_drawer";
  if (state.phone?.overlay?.mode === "private-create") return "private_taotao_sheet";
  if (state.phone?.overlay) return "explicit_detail_sheet";
  if ((state.phone?.messages ?? []).some((message) => (Array.isArray(message) ? Boolean(message[3]) : Boolean(message.capability)))) return "message_attached_capsule";
  if (state.phone?.inlineCard) return "inline_card_legacy";
  return "chat_message_stream";
};

const inferSourceAnchor = (state) => {
  const overlaySource = state.phone?.overlay?.sourceMessageId ?? state.phone?.overlay?.sourceCapabilityId;
  if (overlaySource) return overlaySource;
  const capabilitySource = (state.phone?.messages ?? []).find((message) => {
    const capability = Array.isArray(message) ? message[3] : message.capability;
    return capability?.sourceMessageId || capability?.id;
  });
  if (capabilitySource) {
    const capability = Array.isArray(capabilitySource) ? capabilitySource[3] : capabilitySource.capability;
    return capability.sourceMessageId ?? capability.id;
  }
  return state.id;
};

const makeActionContracts = (actions = []) =>
  actions.map((label) => {
    const actionId = actionIdByLabel[label] ?? label;
    return {
      label,
      actionId,
      nextStateId: nextStateByActionId[actionId] ?? "state_defined_by_current_flow",
    };
  });

const getOverlayActionLabels = (overlay) => [
  ...(overlay?.actions ?? []),
  ...(overlay?.suggestions?.map((item) => item.title) ?? []),
];

const makeState = (state) => {
  const visibility = state.visibility ?? "group";
  const visibilityScope = state.visibilityScope ?? visibilityScopeByVisibility[visibility];
  const objectType = state.objectType ?? objectTypeByIntent[state.intent] ?? "taotao_reply";
  const lifecycleStatus = state.lifecycleStatus ?? "sent";
  const participantStatus = state.participantStatus ?? (visibility === "private" ? "not_visible" : "visible");
  const flowId = state.flowId ?? flowIdByIntent[state.intent] ?? "triad_chat";
  const review = {
    ...baseReview,
    ...state.review,
  };
  const productionContract = {
    flowId,
    trigger: state.trigger,
    surface: inferStateSurface(state),
    visibility: visibilityScope,
    participantStatus,
    lifecycleStatus,
    next: state.next,
    recovery: review.recovery,
    sourceAnchor: inferSourceAnchor(state),
    mustNot: "手机界面不显示技术字段、状态机语言或评审说明。",
    actions: makeActionContracts(getOverlayActionLabels(state.phone?.overlay).length ? getOverlayActionLabels(state.phone?.overlay) : state.phone?.inlineCard?.actions ?? []),
    ...state.productionContract,
  };

  return {
    owner: "PM / Design / Frontend",
    phase: "V8 production flow contract on V7.8 chat surface",
    priority: state.priority ?? "P0",
    visibility,
    objectType,
    lifecycleStatus,
    visibilityScope,
    participantStatus,
    flowId,
    productionContract,
    apiContract: state.apiContract ?? `chat_surface_${state.id}`,
    analyticsKey: state.analyticsKey ?? `taotao_v78_${state.id}`,
    ...state,
    phone: {
      kind: state.phone?.gate ? "gate" : "chat",
      ...state.phone,
    },
    review,
  };
};

