export function getV72ChatBoardStats() {
  const capsuleCount = chatDisplayStates.filter((state) => state.capsule !== "none").length;
  const overlayCount = chatDisplayStates.filter((state) => state.overlay === "active").length;
  const capabilityCount = chatDisplayStates.reduce((count, state) => {
    return count + (state.phone.messages ?? []).filter((message) => {
      if (Array.isArray(message)) return Boolean(message[3]);
      return Boolean(message.capability);
    }).length;
  }, 0);
  const quietCapsuleCount = chatDisplayStates.filter((state) => ["idle", "rotating", "quiet"].includes(state.capsule)).length;
  const preconditionCount = chatDisplayStates.filter((state) => state.phone.kind === "gate").length;
  return {
    stateCount: chatDisplayStates.length,
    capsuleCount,
    overlayCount,
    capabilityCount,
    noCapsuleCount: quietCapsuleCount,
    preconditionCount,
  };
}
